query {
  viewer {
    accounts(filter: {accountTag: "${accountTag}"}) {
      magicTransitNetworkAnalyticsAdaptiveGroups(
        limit: 10000
        filter: {
          datetime_geq: "${__from:date:iso}"
          datetime_lt: "${__to:date:iso}"
          outcome: "pass"
        }
        orderBy: [datetimeFiveMinutes_ASC, avg_packetRateFiveMinutes_DESC]
      ) {
        dimensions {
          datetimeFiveMinutes
          ipDestinationSubnet
        }
        avg {
          packetRate: packetRateFiveMinutes
        }
      }
    }
  }
}

